def write_json(output_path: Path) -> None:
    """Write the literal JSON payload to disk."""
    output_path.parent.mkdir(parents=True, exist_ok=True)
    output_path.write_text(JSON_TEXT, encoding='utf-8')

def verify_json(output_path: Path) -> None:
    """Ensure output is byte-identical to original JSON text."""
    digest = hashlib.sha256(output_path.read_bytes()).hexdigest()
    if digest != SOURCE_SHA256:
        raise RuntimeError(
            f'SHA mismatch for {output_path}: {digest} != {SOURCE_SHA256}'
        )

def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(
        description='Generate the original JSON payload from a literal Python script.'
    )
    parser.add_argument('--output', default='examples/artifacts/qi_hu_from_json_literal.json', help='Output JSON path')
    parser.add_argument(
        '--verify',
        action='store_true',
        help='Check byte-level identity against source SHA-256',
    )
    return parser.parse_args()

def main() -> None:
    args = parse_args()
    output_path = Path(args.output)
    write_json(output_path)
    if args.verify:
        verify_json(output_path)
    print(f'Written: {output_path}')
    if args.verify:
        print(f'Verified SHA-256: {SOURCE_SHA256}')

if __name__ == '__main__':
    main()
